const ucRow      = $('Carga Use Cases').first().json;
const programs   = $('Carga Programas y TechDocs').all().map(i => i.json);
const filesDb2   = $('Carga Archivos y DB2').all().map(i => i.json);

// Parse use cases
let ucData = {};
try {
  ucData = typeof ucRow.use_cases_json === 'string'
    ? JSON.parse(ucRow.use_cases_json)
    : (ucRow.use_cases_json || {});
} catch(e) {}

const files = filesDb2.filter(r => r.tipo === 'file');
const db2   = filesDb2.filter(r => r.tipo === 'db2');

// ── FUNCTIONAL CONTEXT ────────────────────────────────────────
const groupsSummary = (ucData.groups || []).map(g => {
  const ucList = (g.use_cases || []).map(u => `    - ${u.id}: ${u.title}`).join('\n');
  return `• ${g.id} — ${g.name}: ${g.description}\n  Casos de uso:\n${ucList}`;
}).join('\n\n');

const filesBusiness = files.length
  ? files.map(f => `• ${f.nombre}: utilizado por [${f.programas || '?'}]`).join('\n')
  : 'No detectados';

const db2Business = db2.length
  ? db2.map(d => `• ${d.nombre}: accedido por [${d.programas || '?'}] (ops: ${d.organization || '?'})`).join('\n')
  : 'No detectados';

const functional_context =
`SISTEMA: ${ucData.system_name || 'Sistema COBOL'}
DESCRIPCIÓN: ${ucData.system_description || ''}
TOTAL DE CASOS DE USO: ${ucData.total_use_cases || 0}

MÓDULOS FUNCIONALES Y CASOS DE USO:
${groupsSummary}

ARCHIVOS DE NEGOCIO:
${filesBusiness}

TABLAS DE DATOS:
${db2Business}`;

// ── TECHNICAL CONTEXT ─────────────────────────────────────────
const callsGraph = programs
  .map(p => {
    try {
      const refs = JSON.parse(p.calls_json || '[]');
      if (refs.length) return `• ${p.program_name} → ${refs.join(', ')}`;
    } catch(e) {}
    return null;
  })
  .filter(Boolean)
  .join('\n') || 'No se detectaron llamadas entre programas';

const progsSummary = programs.map(p =>
  `• ${p.program_name} (complejidad: ${p.complexity_score || 'N/A'}, ${p.line_count || '?'} líneas): ${p.description || 'sin descripción'}`
).join('\n');

const filesTech = files.length
  ? files.map(f => `• ${f.nombre} [Org: ${f.organization || '?'}, Acceso: ${f.access_mode || '?'}]: usado por [${f.programas || '?'}]`).join('\n')
  : 'No detectados';

const db2Tech = db2.length
  ? db2.map(d => `• ${d.nombre} (ops: ${d.organization || '?'}): accedido por [${d.programas || '?'}]`).join('\n')
  : 'No detectados';

const technical_context =
`SISTEMA: ${ucData.system_name || 'Sistema COBOL'}
DESCRIPCIÓN: ${ucData.system_description || ''}
TOTAL PROGRAMAS: ${programs.length}

PROGRAMAS (mayor a menor complejidad):
${progsSummary}

GRAFO DE DEPENDENCIAS:
${callsGraph}

ARCHIVOS FÍSICOS:
${filesTech}

TABLAS DB2:
${db2Tech}`;

// ── PROGRAMS DATA (pasado directo, no regenerado por LLM) ─────
const programs_data = programs.map(p => {
  let tech_summary = 'Sin documentación técnica generada aún.';
  if (p.tech_doc) {
    // Primer párrafo significativo del tech doc
    const firstPara = p.tech_doc
      .replace(/^#+.+$/gm, '')
      .split(/\n{2,}/)
      .map(s => s.trim())
      .find(s => s.length > 40) || '';
    tech_summary = firstPara.substring(0, 350) + (firstPara.length > 350 ? '...' : '');
  }
  return {
    name:             p.program_name,
    complexity_score: p.complexity_score ? parseFloat(p.complexity_score) : null,
    line_count:       p.line_count || 0,
    description:      p.description || '',
    tech_summary
  };
});

return {
  json: {
    functional_context,
    technical_context,
    programs_data: JSON.stringify(programs_data),
    system_name: ucData.system_name || 'Sistema COBOL'
  }
};

const chainOut = $input.first().json;
let raw = (chainOut.text || chainOut.output || '').trim();
raw = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```\s*$/i,'').trim();

// Extrae el objeto JSON principal
const s = raw.indexOf('{'), e = raw.lastIndexOf('}');
if (s !== -1 && e > s) raw = raw.substring(s, e + 1);

// Arregla comas finales
raw = raw.replace(/,([\s\r\n]*[}\]])/g, '$1');

// Repair: escapa saltos de línea/tabs reales dentro de strings JSON
function repairJson(str) {
  let out = '', inStr = false, esc = false;
  for (let i = 0; i < str.length; i++) {
    const c = str[i];
    if (esc)        { out += c; esc = false; continue; }
    if (c === '\\') { out += c; esc = true;  continue; }
    if (c === '"')  { inStr = !inStr; out += c; continue; }
    if (inStr) {
      if (c === '\n') { out += '\\n'; continue; }
      if (c === '\r') { out += '\\r'; continue; }
      if (c === '\t') { out += '\\t'; continue; }
    }
    out += c;
  }
  return out;
}

let ob;
try {
  ob = JSON.parse(raw);
} catch(e1) {
  try {
    ob = JSON.parse(repairJson(raw));
  } catch(e2) {
    try {
      const fixed = repairJson(raw).replace(/([{,]\s*)([a-zA-Z_][a-zA-Z0-9_]*)\s*:/g, '$1"$2":');
      ob = JSON.parse(fixed);
    } catch(e3) {
      const pos = parseInt((e1.message.match(/position (\d+)/)||[])[1]) || 0;
      const ctx = raw.substring(Math.max(0,pos-150), pos+150);
      throw new Error(`LLM Funcional - JSON inválido en pos ${pos}: ${e1.message}\nContexto: ...${ctx}...`);
    }
  }
}

const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

const mdToHtml = text => {
  if (!text) return '';
  let h = text
    .replace(/^### (.+)$/gm,'<h4>$1</h4>')
    .replace(/^## (.+)$/gm,'<h3>$1</h3>')
    .replace(/^# (.+)$/gm,'<h2>$1</h2>')
    .replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>')
    .replace(/\*(.+?)\*/g,'<em>$1</em>')
    .replace(/^- (.+)$/gm,'<li>$1</li>')
    .replace(/^\d+\. (.+)$/gm,'<li>$1</li>');
  h = h.replace(/(<li>[\s\S]*?<\/li>\n?)+/g, m => `<ul>${m}</ul>`);
  h = h.split(/\n{2,}/).map(p => {
    p = p.trim();
    if (!p || p.startsWith('<')) return p;
    return `<p>${p}</p>`;
  }).join('\n');
  return h;
};

const chapters = ob.chapters || [];

const tocHtml = chapters.map(ch =>
  `<li><a href="#${ch.id}">${esc(ch.id)}: ${esc(ch.title)}</a></li>`
).join('');

const chaptersHtml = chapters.map(ch => {
  const objHtml = (ch.learning_objectives||[]).map(o=>`<li>${esc(o)}</li>`).join('');
  const kcHtml  = (ch.key_concepts||[]).map(k=>`<li>${esc(k)}</li>`).join('');
  return `
<section class="chapter" id="${ch.id}">
  <div class="ch-header">
    <span class="ch-id">${ch.id}</span>
    <h2>${esc(ch.title)}</h2>
  </div>
  <div class="ch-body">
    <div class="box obj-box"><div class="box-label">📋 Objetivos de aprendizaje</div><ul>${objHtml}</ul></div>
    <div class="ch-content">${mdToHtml(ch.content||'')}</div>
    <div class="box kc-box"><div class="box-label">💡 Conceptos clave</div><ul>${kcHtml}</ul></div>
    <div class="box sum-box"><div class="box-label">📌 En resumen</div><p>${esc(ch.summary||'')}</p></div>
  </div>
</section>`;
}).join('');

