const content_html = `<!DOCTYPE html>
<html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>${esc(ob.title||'')}</title><style>${CSS}</style></head>
<body>
<nav><div class="nav-title">Onboarding</div><span class="profile-badge">Funcional</span><ul>${tocHtml}</ul></nav>
<main>
  <div class="ob-header"><h1>${esc(ob.title||'')}</h1><p>${esc(ob.description||'')}</p></div>
  ${chaptersHtml}
</main></body></html>`;

const mdLines = [`# ${ob.title||'Onboarding Funcional'}`,'',(ob.description||''),''];
for (const ch of chapters) {
  mdLines.push(`## ${ch.id}: ${ch.title}`,'');
  mdLines.push('**Objetivos:**');
  (ch.learning_objectives||[]).forEach(o=>mdLines.push(`- ${o}`));
  mdLines.push('',ch.content||'','');
  mdLines.push('**Conceptos clave:**');
  (ch.key_concepts||[]).forEach(k=>mdLines.push(`- ${k}`));
  mdLines.push('',`> ${ch.summary||''}`,'');
}

return { json: { profile:'functional', chapter_count:chapters.length, content_html, content_md:mdLines.join('\n') } };

